import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Audit Log","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/audit-log.md","filePath":"guide/admin/audit-log.md","lastUpdated":1779094756000}'),d={name:"guide/admin/audit-log.md"};function n(l,t,i,s,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h1><p>The <strong>Audit Log</strong> is the record of every notable action that has happened on the platform — who did what, when, to which entity, and with what metadata. It is read-only and append-only.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>Header with title and description.</li><li>Toolbar — search field plus three filter dropdowns and a <strong>Clear</strong> button.</li><li>Table inside a bordered panel with a fixed-height scrolling area.</li><li>Infinite scroll — more rows load automatically as you near the bottom.</li></ul><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Debounced free-text search over actions (300 ms delay). Placeholder: &quot;Search actions…&quot;</td></tr><tr><td><strong>Entity Type</strong></td><td>Dropdown of every entity type present in the log (Tenant, User, Customer, Release, …).</td></tr><tr><td><strong>Action</strong></td><td>Dropdown of every action name present in the log (<code>user.created</code>, <code>tenant.migrated</code>, …).</td></tr><tr><td><strong>Actor Type</strong></td><td>Dropdown of every actor type (<code>system</code>, <code>user</code>, <code>job</code>, …).</td></tr><tr><td><strong>Clear</strong></td><td>Resets all filters and the search.</td></tr></tbody></table><p>The filter dropdowns are built from the data, so they reflect what is actually in the log — not a hard-coded list.</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Time</strong></td><td>Locale date/time string.</td></tr><tr><td><strong>Action</strong></td><td>Action type in monospace (e.g. <code>user.created</code>).</td></tr><tr><td><strong>Entity</strong></td><td>Type badge followed by the last 8 characters of the entity ID.</td></tr><tr><td><strong>Actor</strong></td><td>Actor type and the last 8 characters of the actor ID.</td></tr><tr><td><strong>Metadata</strong></td><td>JSON key-value pairs in a code block, truncated; hover for full text.</td></tr><tr><td><strong>Copy icon</strong></td><td>On hover. Click to copy the row as tab-separated values. The icon shows a check for 1.5 seconds.</td></tr></tbody></table><p>You can also drag the right edge of a column header to resize it manually.</p><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>When events are present in the table, an <strong>Export XLSX</strong> button appears top right. Clicking it downloads a spreadsheet of the currently loaded events, respecting your active filters.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The metadata column truncates to keep rows scannable. Hover or copy the row to see the full payload.</li><li>The log is the source of truth for compliance and incident review. It is not a debugging tool — for that, look at the per-feature logs (release activity log, migration job phase logs, email logs).</li><li>Action names follow <code>entity.verb</code> (e.g. <code>tenant.migrated</code>). Filtering by action gives you a focused stream for a specific event type.</li><li>The page does not auto-poll. To see fresh entries, scroll to the top and reload, or apply a filter.</li><li>Tab-separated copies paste cleanly into spreadsheets and ticketing systems.</li></ul>',14)])])}const g=e(d,[["render",n]]);export{p as __pageData,g as default};
